package main

import (
	"testing"
)

func TestCheckEnvGate(t *testing.T) {
	tests := []struct {
		name    string
		env     string
		wantErr bool
	}{
		{name: "development allowed", env: "development", wantErr: false},
		{name: "production blocked", env: "production", wantErr: true},
		{name: "staging blocked", env: "staging", wantErr: true},
		{name: "empty blocked", env: "", wantErr: true},
		{name: "random string blocked", env: "dev", wantErr: true},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := checkEnvGate(tt.env)
			if (err != nil) != tt.wantErr {
				t.Errorf("checkEnvGate(%q) error = %v, wantErr %v", tt.env, err, tt.wantErr)
			}
		})
	}
}

