package main

import (
	"context"
	"fmt"
	"log"
	"os"
	"path/filepath"
	"time"

	"github.com/pressly/goose/v3"

	"github.com/ketang/flotsam/api/internal/db"
)

const migrationsDir = "migrations"

func main() {
	if err := run(context.Background(), os.Args[1:]); err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
}

func run(ctx context.Context, args []string) error {
	if len(args) == 0 {
		return usageError("command required")
	}

	switch args[0] {
	case "up":
		return db.MigrateUp(ctx, requireDatabaseURL())
	case "down":
		return db.MigrateDown(ctx, requireDatabaseURL())
	case "status":
		return printStatus(ctx, requireDatabaseURL())
	case "create":
		if len(args) != 2 {
			return usageError("create requires exactly one migration name")
		}
		return goose.Create(nil, migrationsDir, args[1], "sql")
	default:
		return usageError(fmt.Sprintf("unknown command %q", args[0]))
	}
}

func requireDatabaseURL() string {
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		fmt.Fprintln(os.Stderr, "DATABASE_URL is required")
		os.Exit(1)
	}
	return dbURL
}

func printStatus(ctx context.Context, databaseURL string) error {
	statuses, err := db.MigrationStatus(ctx, databaseURL)
	if err != nil {
		return err
	}

	log.Printf("    Applied At                  Migration")
	log.Printf("    =======================================")
	for _, status := range statuses {
		appliedAt := "Pending"
		if status.State == goose.StateApplied {
			appliedAt = status.AppliedAt.Format(time.ANSIC)
		}
		log.Printf("    %-24s -- %v", appliedAt, filepath.Base(status.Source.Path))
	}
	return nil
}

func usageError(msg string) error {
	return fmt.Errorf("%s\nusage: migrate <up|down|status|create>", msg)
}

import { test, expect } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'
const apiBaseURL = process.env.DEMO_API_URL ?? 'http://localhost:8081'

