  test('API health endpoint returns OK', async ({ request }) => {
    const response = await request.get(`${apiBaseURL}/health`)
    expect(response.ok()).toBeTruthy()
  })

  test('Home page loads', async ({ page }) => {
    await page.goto('/')
    await expect(page.getByText('Your second brain')).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Login with seed credentials', async ({ page }) => {
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.locator('form').getByRole('button', { name: 'Login' }).click()

    // After login, redirects to / — verify authenticated state shows Capture button
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Browse page accessible after login', async ({ page }) => {
    // Login first
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.locator('form').getByRole('button', { name: 'Login' }).click()
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    // Navigate to browse
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')

    // Verify page loaded (browse should show items or empty state)
    await expect(page).toHaveURL(/\/browse/)

    if (isManual) await page.pause()
  })
})

import { test, expect, type Page } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'
const uniqueId = `demo-${Date.now()}`

async function login(page: Page) {
  await page.goto('/login')
  await page.getByLabel('Email').fill('ketan@example.com')
  await page.getByLabel('Password').fill('testpassword123')
  await page.locator('form').getByRole('button', { name: 'Login' }).click()
  await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()
}

test.describe('Capture Round-Trip', () => {
  test('Capture a text note and retrieve it', async ({ page }) => {
    const noteTitle = `Demo Note ${uniqueId}`
    const noteContent = `This is a demo text note created during the capture round-trip test. ID: ${uniqueId}`

    await login(page)

    // Navigate to capture and select Note tab
    await page.goto('/capture')
    await page.getByRole('tab', { name: /Note/i }).click()
    const notePanel = page.getByRole('tabpanel', { name: 'Note' })

    // Fill in the note form
    await notePanel.getByLabel('Title').fill(noteTitle)
    await notePanel.getByLabel('Content').fill(noteContent)

    if (isManual) await page.pause()

    // Submit
    await page.getByRole('button', { name: 'Save Note' }).click()

    // Success redirects to /
    await expect(page).toHaveURL('/')

    // Navigate to browse and find the note
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')
    await expect(page.getByText(noteTitle)).toBeVisible()

    if (isManual) await page.pause()

    // Click into the note and verify detail page
    await page.getByText(noteTitle).click()
    await expect(page).toHaveURL(/\/items\//)
    await expect(page.getByText(noteTitle)).toBeVisible()
    await expect(page.getByText(noteContent)).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Capture a bookmark and retrieve it', async ({ page }) => {
    const bookmarkTitle = `Demo Bookmark ${uniqueId}`
    const bookmarkUrl = `https://example.com/${uniqueId}`

    await login(page)

    // Navigate to capture — Bookmark tab is default
    await page.goto('/capture')
    const bookmarkPanel = page.getByRole('tabpanel', { name: 'Bookmark' })

    // Fill in the bookmark form
    await bookmarkPanel.getByLabel('URL').fill(bookmarkUrl)
    await bookmarkPanel.getByLabel('Title').fill(bookmarkTitle)

    if (isManual) await page.pause()

    // Submit
    await page.getByRole('button', { name: 'Save Bookmark' }).click()

    // Success redirects to /
    await expect(page).toHaveURL('/')

    // Navigate to browse and find the bookmark
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')
    await expect(page.getByText(bookmarkTitle)).toBeVisible()

    if (isManual) await page.pause()

    // Click into the bookmark and verify detail page
    await page.getByText(bookmarkTitle).click()
    await expect(page).toHaveURL(/\/items\//)
    await expect(page.getByText(bookmarkTitle)).toBeVisible()
    await expect(page.getByText(bookmarkUrl)).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Search retrieves captured items', async ({ page }) => {
    const searchNoteTitle = `Search Note ${uniqueId}`
    const searchNoteContent = `Searchable content for round-trip verification. ID: ${uniqueId}`

    await login(page)

    // Capture a note first
    await page.goto('/capture')
    await page.getByRole('tab', { name: /Note/i }).click()
    const notePanel = page.getByRole('tabpanel', { name: 'Note' })
    await notePanel.getByLabel('Title').fill(searchNoteTitle)
    await notePanel.getByLabel('Content').fill(searchNoteContent)
    await page.getByRole('button', { name: 'Save Note' }).click()
    await expect(page).toHaveURL('/')

    // Search for the note
    await page.goto('/search')
    await page.getByPlaceholder('Search your knowledge base...').fill(searchNoteTitle)
    // Press Enter or wait for results — search may auto-trigger or need submit
    await page.getByPlaceholder('Search your knowledge base...').press('Enter')
    await page.waitForLoadState('networkidle')

    await expect(page.getByText(searchNoteTitle)).toBeVisible()

    if (isManual) await page.pause()
  })
})

import { defineConfig, devices } from '@playwright/test'

const mode = (process.env.DEMO_MODE ?? 'auto') as 'auto' | 'manual' | 'headless'
const demoWebURL = process.env.DEMO_WEB_URL ?? 'http://localhost:8080'

const modeSettings = {
  auto: { headless: false, slowMo: 800, trace: 'on' as const },
  manual: { headless: false, slowMo: 0, trace: 'on' as const },
  headless: { headless: true, slowMo: 0, trace: 'on-first-retry' as const },
}

const settings = modeSettings[mode] ?? modeSettings.auto

export default defineConfig({
  testDir: './tests',
  fullyParallel: false,
  workers: 1,
  retries: 0,
  timeout: 30_000,

  reporter: [
    ['html', { outputFolder: '../logs/demo/report', open: 'never' }],
    ['list'],
  ],

  outputDir: '../logs/demo/artifacts',

  use: {
    baseURL: demoWebURL,
    headless: settings.headless,
    trace: settings.trace,
    ...devices['Desktop Chrome'],
    launchOptions: {
      slowMo: settings.slowMo,
    },
  },

  projects: [
    {
      name: 'boot-verification',
      testMatch: /boot-verification\.spec\.ts/,
    },
    {
      name: 'web-walkthrough',
      testMatch: /web-walkthrough\.spec\.ts/,
    },
    {
      name: 'capture-round-trip',
      testMatch: /capture-round-trip\.spec\.ts/,
    },
    {
      name: 'mcp-walkthrough',
      testMatch: /mcp-walkthrough\.spec\.ts/,
    },
    {
      name: 'voice-demo',
      testMatch: /voice-demo\.spec\.ts/,
    },
  ],
})

